section.programlisting:
-- ============================================================================= -- Hive DDL: u.s. debt held by china -- Generated by load_china_debt_into_singine.py -- Parquet source: us_debt_held_by_china.parquet -- =============================================================================
-- EXTERNAL TABLE (point at the directory containing the parquet file) CREATE EXTERNAL TABLE IF NOT EXISTS china_us_debt ( date DATE COMMENT 'Observation or projection date', amount_held_by_china BIGINT COMMENT 'USD billions, rounded to nearest billion', event_description STRING COMMENT 'Historical event or projection assumption note', projection_flag BOOLEAN COMMENT 'true = projected, false = historical' ) STORED AS PARQUET LOCATION 'hdfs:///data/finance/china_us_debt/' TBLPROPERTIES ( 'parquet.compress'='SNAPPY', 'comment'='U.S. national debt held by China 1990-2220, historical + projected' );
-- Verify load SELECT COUNT(*) AS total_rows, SUM(CASE WHEN projection_flag = false THEN 1 ELSE 0 END) AS historical_rows, SUM(CASE WHEN projection_flag = true THEN 1 ELSE 0 END) AS projected_rows FROM china_us_debt;

-- ============================================================================= -- Analytical SQL: U.S. Debt Held by China -- Compatible with: Hive, Spark SQL, Presto/Trino, DuckDB -- =============================================================================
-- ── Q1: Full historical time series (sorted) ────────────────────────────────── SELECT date, amount_held_by_china, event_description FROM china_us_debt WHERE projection_flag = false ORDER BY date;
-- ── Q2: Peak holding (all-time maximum) ────────────────────────────────────── SELECT date, amount_held_by_china, event_description FROM china_us_debt WHERE projection_flag = false ORDER BY amount_held_by_china DESC LIMIT 1;
-- ── Q3: Year-over-year change (historical only) ─────────────────────────────── SELECT curr.date AS date, curr.amount_held_by_china AS amount_usd_bn, prev.amount_held_by_china AS prev_amount_usd_bn, (curr.amount_held_by_china - prev.amount_held_by_china) AS yoy_change_bn, ROUND( 100.0 * (curr.amount_held_by_china - prev.amount_held_by_china) / prev.amount_held_by_china, 2 ) AS yoy_pct_change FROM china_us_debt curr JOIN china_us_debt prev ON YEAR(curr.date) = YEAR(prev.date) + 1 AND MONTH(curr.date) = 1 AND MONTH(prev.date) = 1 WHERE curr.projection_flag = false AND prev.projection_flag = false ORDER BY curr.date;
-- ── Q4: Decade-level summary (historical) ──────────────────────────────────── SELECT FLOOR(YEAR(date) / 10) * 10 AS decade, MIN(amount_held_by_china) AS min_bn, MAX(amount_held_by_china) AS max_bn, ROUND(AVG(amount_held_by_china), 0) AS avg_bn, COUNT(*) AS observations FROM china_us_debt WHERE projection_flag = false GROUP BY FLOOR(YEAR(date) / 10) * 10 ORDER BY decade;
-- ── Q5: Key crisis / event observations ───────────────────────────────────── SELECT date, amount_held_by_china, event_description FROM china_us_debt WHERE projection_flag = false AND event_description IS NOT NULL AND ( date IN ( DATE '2001-12-11', -- WTO accession DATE '2008-09-15', -- Lehman collapse DATE '2010-10-01', -- Peak as largest holder DATE '2013-11-01', -- All-time peak DATE '2015-08-11', -- RMB devaluation DATE '2018-07-06', -- Trade war begins DATE '2022-02-24', -- Russia invasion / sanctions shock DATE '2022-12-31' -- Largest annual decline on record ) ) ORDER BY date;
-- ── Q6: Inflection points — largest single-period drops ────────────────────── SELECT curr.date, curr.amount_held_by_china, (curr.amount_held_by_china - prev.amount_held_by_china) AS change_bn, curr.event_description FROM china_us_debt curr JOIN china_us_debt prev
